require "net/http"
require "json"

class SendgridMailer < ApplicationMailer
  class DeliveryError < StandardError; end

  DEFAULT_FROM = ENV["DEFAULT_FROM"].presence || "no-reply@example.com"

  def send_email(to:, subject:, content:, from: DEFAULT_FROM, reply_to: nil, cc: nil, bcc: nil, categories: nil, custom_args: nil, attachments: nil)
    payload = build_payload(
      to: to,
      subject: subject,
      content: content,
      from: from,
      reply_to: reply_to,
      cc: cc,
      bcc: bcc,
      categories: categories,
      custom_args: custom_args,
      attachments: attachments
    )

    deliver_via_sendgrid!(payload)

    mail(to: Array(to), from: from, subject: subject) do |format|
      format.text { render plain: strip_html(content) }
      format.html { render html: content.to_s.html_safe }
    end
  end

  private

  def deliver_via_sendgrid!(payload)
    api_key = ENV["SENDGRID_API_KEY"].to_s
    raise DeliveryError, "Missing SENDGRID_API_KEY" if api_key.empty?

    uri = URI("https://api.sendgrid.com/v3/mail/send")
    http = Net::HTTP.new(uri.host, uri.port)
    http.use_ssl = true

    req = Net::HTTP::Post.new(uri.request_uri)
    req["Authorization"] = "Bearer #{api_key}"
    req["Content-Type"] = "application/json"
    req["User-Agent"] = "RailsSendgridMailer/#{Rails.version}"
    req.body = JSON.generate(payload)

    res = http.request(req)

    return if res.code.to_i == 202

    message = begin
      body = res.body.to_s
      parsed = body.empty? ? {} : JSON.parse(body)
      if parsed.is_a?(Hash) && parsed["errors"].is_a?(Array)
        parsed["errors"].map { |e| e["message"] || e.to_s }.join(", ")
      else
        body
      end
    rescue StandardError
      res.body.to_s
    end

    raise DeliveryError, "SendGrid delivery failed (#{res.code}): #{message}"
  end

  def build_payload(to:, subject:, content:, from:, reply_to:, cc:, bcc:, categories:, custom_args:, attachments:)
    to_list = normalize_emails(to)
    cc_list = normalize_emails(cc)
    bcc_list = normalize_emails(bcc)

    personalization = { "to" => to_list }
    personalization["cc"] = cc_list if cc_list.any?
    personalization["bcc"] = bcc_list if bcc_list.any?
    personalization["custom_args"] = custom_args if custom_args.present?

    payload = {
      "personalizations" => [personalization],
      "from" => { "email" => from },
      "subject" => subject.to_s,
      "content" => [
        { "type" => "text/plain", "value" => strip_html(content) },
        { "type" => "text/html", "value" => content.to_s }
      ]
    }

    payload["reply_to"] = { "email" => reply_to } if reply_to.present?
    payload["categories"] = Array(categories).map(&:to_s) if categories.present?
    payload["attachments"] = normalize_attachments(attachments) if attachments.present?

    payload
  end

  def normalize_emails(value)
    Array(value).compact.map do |v|
      if v.is_a?(Hash)
        email = v[:email] || v["email"]
        name = v[:name] || v["name"]
        h = { "email" => email.to_s }
        h["name"] = name.to_s if name.present?
        h
      else
        { "email" => v.to_s }
      end
    end.reject { |h| h["email"].empty? }
  end

  def normalize_attachments(value)
    Array(value).compact.map do |att|
      if att.is_a?(Hash)
        {
          "content" => att[:content] || att["content"],
          "type" => att[:type] || att["type"],
          "filename" => att[:filename] || att["filename"],
          "disposition" => att[:disposition] || att["disposition"] || "attachment",
          "content_id" => att[:content_id] || att["content_id"]
        }.compact
      else
        raise ArgumentError, "Attachment must be a Hash"
      end
    end
  end

  def strip_html(html)
    ActionView::Base.full_sanitizer.sanitize(html.to_s).to_s
  end
