require "net/http"
require "json"

class SendgridApiDelivery
  class DeliveryError < StandardError; end

  def initialize(options = {})
    @api_key = options[:api_key] || ENV["SENDGRID_API_KEY"]
    @default_from = options[:default_from] || ENV["DEFAULT_FROM"]
  end

  def deliver!(mail)
    api_key = @api_key.to_s
    raise DeliveryError, "Missing SENDGRID_API_KEY" if api_key.empty?

    from_email = (mail.from&.first || @default_from).to_s
    raise DeliveryError, "Missing from email" if from_email.empty?

    to_emails = Array(mail.to).compact
    raise DeliveryError, "Missing recipient email" if to_emails.empty?

    subject = mail.subject.to_s
    html_part = mail.html_part&.body&.decoded
    text_part = mail.text_part&.body&.decoded

    if html_part.nil? && text_part.nil?
      body = mail.body&.decoded.to_s
      html_part = body
      text_part = ActionView::Base.full_sanitizer.sanitize(body)
    end

    payload = {
      "personalizations" => [
        {
          "to" => to_emails.map { |e| { "email" => e } },
          "cc" => Array(mail.cc).compact.map { |e| { "email" => e } },
          "bcc" => Array(mail.bcc).compact.map { |e| { "email" => e } }
        }.compact
      ],
      "from" => { "email" => from_email },
      "subject" => subject,
      "content" => []
    }

    payload["reply_to"] = { "email" => mail.reply_to.first } if mail.reply_to.present?

    if text_part.present?
      payload["content"] << { "type" => "text/plain", "value" => text_part.to_s }
    end
    if html_part.present?
      payload["content"] << { "type" => "text/html", "value" => html_part.to_s }
    end

    uri = URI("https://api.sendgrid.com/v3/mail/send")
    http = Net::HTTP.new(uri.host, uri.port)
    http.use_ssl = true

    req = Net::HTTP::Post.new(uri.request_uri)
    req["Authorization"] = "Bearer #{api_key}"
    req["Content-Type"] = "application/json"
    req["User-Agent"] = "RailsSendgridApiDelivery/#{Rails.version}"
    req.body = JSON.generate(payload)

    res = http.request(req)
    return if res.code.to_i == 202

    message = begin
      body = res.body.to_s
      parsed = body.empty? ? {} : JSON.parse(body)
      if parsed.is_a?(Hash) && parsed["errors"].is_a?(Array)
        parsed["errors"].map { |e| e["message"] || e.to_s }.join(", ")
      else
        body
      end
    rescue StandardError
      res.body.to_s
    end

    raise DeliveryError, "SendGrid delivery failed (#{res.code}): #{message}"
  end
end

